  1→import { existsSync, mkdirSync } from "fs";
  2→import { appendFile } from "fs/promises";
  3→import { join, dirname } from "path";
  4→import chalk from "chalk";
  5→import type { MultiBar } from "cli-progress";
  6→
  7→// Define log levels
  8→export type LogLevel = "debug" | "info" | "warn" | "error";
  9→
 10→// Interface for logger configuration
 11→export interface LoggerConfig {
 12→  logToConsole: boolean;
 13→  logToFile: boolean;
 14→  logFilePath?: string;
 15→  consoleLogLevel: LogLevel; // Separate level for console
 16→  fileLogLevel: LogLevel; // Separate level for file
 17→  multibar?: MultiBar | null;
 18→}
 19→
 20→// Default configuration
 21→const defaultConfig: LoggerConfig = {
 22→  logToConsole: true,
 23→  logToFile: false,
 24→  consoleLogLevel: "info", // Default console level
 25→  fileLogLevel: "debug", // Default file level to debug
 26→  multibar: null,
 27→};
 28→
 29→// Current configuration
 30→let currentConfig: LoggerConfig = { ...defaultConfig };
 31→
 32→/**
 33→ * Configure the logger
 34→ * @param config Configuration options
 35→ */
 36→export function configureLogger(config: Partial<LoggerConfig>): void {
 37→  // Ensure default fileLogLevel is debug if file logging is enabled but level not specified
 38→  if (
 39→    config.logToFile === true &&
 40→    config.logFilePath &&
 41→    config.fileLogLevel === undefined
 42→  ) {
 43→    config.fileLogLevel = "debug";
 44→  }
 45→  currentConfig = { ...currentConfig, ...config };
 46→
 47→  // Create log directory if logging to file
 48→  if (currentConfig.logToFile && currentConfig.logFilePath) {
 49→    const logDir = dirname(currentConfig.logFilePath);
 50→    if (logDir && !existsSync(logDir)) {
 51→      try {
 52→        mkdirSync(logDir, { recursive: true });
 53→      } catch (error) {
 54→        console.error(`Failed to create log directory: ${error}`);
 55→        currentConfig.logToFile = false;
 56→      }
 57→    }
 58→  }
 59→}
 60→
 61→/**
 62→ * Sets or clears the active MultiBar instance for the logger
 63→ * @param multibar The cli-progress MultiBar instance or null
 64→ */
 65→export function setActiveMultibar(multibar: MultiBar | null): void {
 66→  currentConfig.multibar = multibar;
 67→}
 68→
 69→/**
 70→ * Numeric value for log level (for filtering)
 71→ */
 72→const logLevelValue: Record<LogLevel, number> = {
 73→  debug: 0,
 74→  info: 1,
 75→  warn: 2,
 76→  error: 3,
 77→};
 78→
 79→/** Checks if a level should be logged to a specific target (console or file). */
 80→function shouldLog(level: LogLevel, target: "console" | "file"): boolean {
 81→  const threshold =
 82→    target === "console"
 83→      ? currentConfig.consoleLogLevel
 84→      : currentConfig.fileLogLevel;
 85→  return logLevelValue[level] >= logLevelValue[threshold];
 86→}
 87→
 88→/**
 89→ * Format a log message with timestamp and level
 90→ */
 91→function formatLogMessage(level: LogLevel, message: string): string {
 92→  const timestamp = new Date().toISOString();
 93→  return `[${timestamp}] [${level.toUpperCase()}] ${message}`;
 94→}
 95→
 96→/**
 97→ * Internal function to handle console logging (with MultiBar awareness)
 98→ */
 99→function logToConsole(
100→  level: LogLevel,
101→  formattedMessage: string,
102→  coloredMessage: string
103→): void {
104→  if (!currentConfig.logToConsole || !shouldLog(level, "console")) return; // Check console level
105→
106→  let messageForConsole = coloredMessage;
107→  if (currentConfig.multibar && currentConfig.logToFile && level === "error") {
108→    messageForConsole += chalk.gray(" (See log file for full details)");
109→  }
110→
111→  if (currentConfig.multibar) {
112→    currentConfig.multibar.log(`${messageForConsole}\n`);
113→  } else {
114→    // Standard console logging
115→    switch (level) {
116→      case "debug":
117→        console.debug(messageForConsole);
118→        break;
119→      case "info":
120→        console.info(messageForConsole);
121→        break;
122→      case "warn":
123→        console.warn(messageForConsole);
124→        break;
125→      case "error":
126→        console.error(messageForConsole);
127→        break;
128→    }
129→  }
130→}
131→
132→/** Write log to file if configured AND level meets file threshold. */
133→async function logToFile(
134→  level: LogLevel,
135→  formattedMessage: string,
136→  context?: string
137→): Promise<void> {
138→  // Check file logging enabled AND file log level threshold
139→  if (
140→    !currentConfig.logToFile ||
141→    !currentConfig.logFilePath ||
142→    !shouldLog(level, "file")
143→  )
144→    return;
145→
146→  let messageToWrite = formattedMessage;
147→  // Always include full context (like stack trace) in file log if present
148→  if (context) {
149→    messageToWrite += `\n  Context: ${context}`;
150→  }
151→
152→  try {
153→    await appendFile(currentConfig.logFilePath, messageToWrite + "\n");
154→  } catch (error) {
155→    console.error(`[Logger Error] Failed to write to log file: ${error}`);
156→  }
157→}
158→
159→/**
160→ * Log a debug message
161→ */
162→export function debug(message: string, context?: string): void {
163→  if (!shouldLog("debug", "console") && !shouldLog("debug", "file")) return;
164→  const formattedMessage = formatLogMessage("debug", message);
165→  logToConsole("debug", formattedMessage, chalk.gray(formattedMessage));
166→  logToFile("debug", formattedMessage, context);
167→}
168→
169→/**
170→ * Log an info message
171→ */
172→export function info(message: string, context?: string): void {
173→  if (!shouldLog("info", "console") && !shouldLog("info", "file")) return;
174→  const formattedMessage = formatLogMessage("info", message);
175→  logToConsole("info", formattedMessage, chalk.blue(formattedMessage));
176→  logToFile("info", formattedMessage, context);
177→}
178→
179→/**
180→ * Log a warning message
181→ */
182→export function warn(message: string, context?: string): void {
183→  if (!shouldLog("warn", "console") && !shouldLog("warn", "file")) return;
184→  const formattedMessage = formatLogMessage("warn", message);
185→  logToConsole("warn", formattedMessage, chalk.yellow(formattedMessage));
186→  logToFile("warn", formattedMessage, context);
187→}
188→
189→/**
190→ * Log an error message
191→ */
192→export function error(message: string, context?: string): void {
193→  if (!shouldLog("error", "console") && !shouldLog("error", "file")) return;
194→  const formattedMessage = formatLogMessage("error", message);
195→  logToConsole("error", formattedMessage, chalk.red(formattedMessage));
196→  logToFile("error", formattedMessage, context); // Pass context here
197→}
198→
199→/**
200→ * Log a success message (info level with green color)
201→ */
202→export function success(message: string, context?: string): void {
203→  if (!shouldLog("info", "console") && !shouldLog("info", "file")) return;
204→  const formattedMessage = formatLogMessage("info", message);
205→  logToConsole("info", formattedMessage, chalk.green(formattedMessage));
206→  logToFile("info", formattedMessage, context);
207→}
