  1→import { existsSync, mkdirSync, statSync } from "fs";
  2→import { writeFile, readFile } from "fs/promises";
  3→import { join, dirname, basename } from "path";
  4→import * as logger from "./logger";
  5→
  6→/**
  7→ * Ensure a directory exists, creating it if necessary
  8→ * @param dirPath Path to the directory
  9→ * @returns True if successful, false otherwise
 10→ */
 11→export function ensureDir(dirPath: string): boolean {
 12→  try {
 13→    if (!existsSync(dirPath)) {
 14→      mkdirSync(dirPath, { recursive: true });
 15→      logger.debug(`Created directory: ${dirPath}`);
 16→    }
 17→    return true;
 18→  } catch (error) {
 19→    logger.error(`Failed to create directory ${dirPath}: ${error}`);
 20→    return false;
 21→  }
 22→}
 23→
 24→/**
 25→ * Write data to a file, ensuring its directory exists
 26→ * @param filePath Path to the file
 27→ * @param data Data to write (string or object to be stringified)
 28→ * @returns Promise that resolves to true if successful
 29→ */
 30→export async function writeToFile(
 31→  filePath: string,
 32→  data: string | object
 33→): Promise<boolean> {
 34→  try {
 35→    const dir = dirname(filePath);
 36→    ensureDir(dir);
 37→
 38→    const content =
 39→      typeof data === "string" ? data : JSON.stringify(data, null, 2);
 40→    await writeFile(filePath, content, "utf-8");
 41→    logger.debug(`Wrote to file: ${filePath}`);
 42→    return true;
 43→  } catch (error) {
 44→    logger.error(`Failed to write to file ${filePath}: ${error}`);
 45→    return false;
 46→  }
 47→}
 48→
 49→/**
 50→ * Read data from a file
 51→ * @param filePath Path to the file
 52→ * @returns Promise that resolves to the file contents or null if error
 53→ */
 54→export async function readFromFile(filePath: string): Promise<string | null> {
 55→  try {
 56→    if (!existsSync(filePath)) {
 57→      logger.warn(`File does not exist: ${filePath}`);
 58→      return null;
 59→    }
 60→
 61→    const content = await readFile(filePath, "utf-8");
 62→    logger.debug(`Read from file: ${filePath}`);
 63→    return content;
 64→  } catch (error) {
 65→    logger.error(`Failed to read from file ${filePath}: ${error}`);
 66→    return null;
 67→  }
 68→}
 69→
 70→/**
 71→ * Read and parse a JSON file
 72→ * @param filePath Path to the JSON file
 73→ * @returns Promise that resolves to the parsed object or null if error
 74→ */
 75→export async function readJsonFromFile<T>(filePath: string): Promise<T | null> {
 76→  try {
 77→    const content = await readFromFile(filePath);
 78→    if (!content) return null;
 79→
 80→    return JSON.parse(content) as T;
 81→  } catch (error) {
 82→    logger.error(`Failed to parse JSON from file ${filePath}: ${error}`);
 83→    return null;
 84→  }
 85→}
 86→
 87→/**
 88→ * Check if a file exists and is not empty
 89→ * @param filePath Path to the file
 90→ * @returns True if the file exists and has content
 91→ */
 92→export function fileExistsWithContent(filePath: string): boolean {
 93→  try {
 94→    if (!existsSync(filePath)) {
 95→      return false;
 96→    }
 97→
 98→    const stats = statSync(filePath);
 99→    return stats.isFile() && stats.size > 0;
100→  } catch (error) {
101→    logger.error(`Error checking file ${filePath}: ${error}`);
102→    return false;
103→  }
104→}
105→
106→/**
107→ * Generate output path for a processed file
108→ * @param baseDir Base directory for output
109→ * @param inputPath Original input file path
110→ * @param suffix Suffix to add to the filename
111→ * @param extension New extension (without dot)
112→ * @returns Full path for the output file
113→ */
114→export function generateOutputPath(
115→  baseDir: string,
116→  inputPath: string,
117→  suffix: string,
118→  extension: string
119→): string {
120→  const filename = basename(inputPath).split(".")[0];
121→  return join(baseDir, `${filename}${suffix}.${extension}`);
122→}
