  1→import { readFile } from "fs/promises";
  2→import type { SrtEntry } from "../types.js"; // Assuming SrtEntry is in types.ts
  3→import {
  4→  parseSrtTiming,
  5→  formatSrtTiming,
  6→  secondsToTimestamp,
  7→} from "./time_utils.js"; // Assuming time utils are here
  8→import * as logger from "./logger.js";
  9→
 10→/**
 11→ * Parse an SRT file into SrtEntry objects, applying an optional time offset.
 12→ * @param filePath Path to the SRT file.
 13→ * @param offsetSeconds Optional offset in seconds to apply to all timestamps.
 14→ * @returns Promise resolving to an array of SrtEntry objects, or null if error.
 15→ */
 16→export async function parseSrtFile(
 17→  filePath: string,
 18→  offsetSeconds: number = 0 // Default offset to 0
 19→): Promise<SrtEntry[] | null> {
 20→  try {
 21→    logger.debug(
 22→      `Parsing SRT file: ${filePath}` +
 23→        (offsetSeconds ? ` with offset: ${offsetSeconds}s` : "")
 24→    );
 25→    const content = await readFile(filePath, "utf-8");
 26→
 27→    // Remove BOM if present
 28→    const cleanContent =
 29→      content.charCodeAt(0) === 0xfeff ? content.slice(1) : content;
 30→
 31→    // Split into subtitle blocks (separated by blank lines)
 32→    // Handles both \n and \r\n line endings more robustly
 33→    const blocks = cleanContent
 34→      .split(/\r?\n\r?\n/)
 35→      .filter((block) => block.trim().length > 0);
 36→    const entries: SrtEntry[] = [];
 37→
 38→    for (const block of blocks) {
 39→      const lines = block.split(/\r?\n/);
 40→
 41→      if (lines.length < 3) {
 42→        logger.warn(
 43→          `[SRT Parser] Malformed block (too few lines): ${
 44→            block.split(/\r?\n/)[0]
 45→          }`
 46→        );
 47→        continue;
 48→      }
 49→
 50→      const id = parseInt(lines[0].trim());
 51→      if (isNaN(id)) {
 52→        logger.warn(
 53→          `[SRT Parser] Malformed block (invalid ID): ${lines[0].trim()}`
 54→        );
 55→        continue;
 56→      }
 57→
 58→      const originalTimingString = lines[1].trim();
 59→      const timing = parseSrtTiming(originalTimingString);
 60→      if (!timing) {
 61→        logger.warn(
 62→          `[SRT Parser] Malformed block (invalid timing): ${originalTimingString}`
 63→        );
 64→        continue;
 65→      }
 66→
 67→      // Apply offset
 68→      const offsettedStartTime = timing.startTimeSeconds + offsetSeconds;
 69→      const offsettedEndTime = timing.endTimeSeconds + offsetSeconds;
 70→
 71→      // Skip entry if offset results in negative times
 72→      if (offsettedStartTime < 0 || offsettedEndTime < 0) {
 73→        logger.warn(
 74→          `[SRT Parser] Skipping entry ID ${id} due to negative timestamp after applying offset ${offsetSeconds}s (Original: ${originalTimingString})`
 75→        );
 76→        continue;
 77→      }
 78→
 79→      // Regenerate timing string with offsetted values
 80→      const newTimingString = formatSrtTiming(
 81→        offsettedStartTime,
 82→        offsettedEndTime
 83→      );
 84→
 85→      const text = lines.slice(2).join("\n");
 86→
 87→      entries.push({
 88→        id,
 89→        timingString: newTimingString, // Store the *new* timing string
 90→        startTimeSeconds: offsettedStartTime, // Store offsetted seconds
 91→        endTimeSeconds: offsettedEndTime, // Store offsetted seconds
 92→        text,
 93→      });
 94→    }
 95→
 96→    // Sort by start time just in case
 97→    entries.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
 98→
 99→    logger.debug(
100→      `[SRT Parser] Parsed and offsetted ${entries.length} subtitles from ${filePath}`
101→    );
102→    return entries;
103→  } catch (error) {
104→    logger.error(`[SRT Parser] Failed to parse SRT file ${filePath}: ${error}`);
105→    return null;
106→  }
107→}
108→
109→/**
110→ * Calculates the total time span covered by a list of SRT entries.
111→ * @param entries An array of SrtEntry objects.
112→ * @returns The time span in seconds, or 0 if no entries.
113→ */
114→export function calculateSrtTimeSpan(entries: SrtEntry[]): number {
115→  if (!entries || entries.length === 0) {
116→    return 0;
117→  }
118→  // Entries should already be sorted by parseSrtFile, but sort again just in case
119→  entries.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
120→  const firstStartTime = entries[0].startTimeSeconds;
121→  const lastEndTime = Math.max(...entries.map((e) => e.endTimeSeconds));
122→  return lastEndTime - firstStartTime;
123→}
