  1→/**
  2→ * Time utilities for handling timestamps and durations
  3→ */
  4→
  5→/**
  6→ * Converts seconds to a timestamp string in format HH:MM:SS,mmm
  7→ * @param seconds Total seconds (can include fractional seconds)
  8→ * @returns Formatted timestamp string
  9→ */
 10→export function secondsToTimestamp(seconds: number): string {
 11→  const hours = Math.floor(seconds / 3600);
 12→  const minutes = Math.floor((seconds % 3600) / 60);
 13→  const secs = Math.floor(seconds % 60);
 14→  const ms = Math.floor((seconds % 1) * 1000);
 15→
 16→  return `${hours.toString().padStart(2, "0")}:${minutes
 17→    .toString()
 18→    .padStart(2, "0")}:${secs.toString().padStart(2, "0")},${ms
 19→    .toString()
 20→    .padStart(3, "0")}`;
 21→}
 22→
 23→/**
 24→ * Converts a timestamp string in format HH:MM:SS,mmm to seconds
 25→ * @param timestamp Timestamp string (supports both comma and period as decimal separator)
 26→ * @returns Total seconds as a number
 27→ */
 28→export function timestampToSeconds(timestamp: string): number {
 29→  // Handle formats like 00:14:58,840 or 00:14:58.840
 30→  const timeStr = timestamp.replace(",", ".");
 31→  const [timeWithoutMs, ms] = timeStr.split(".");
 32→  const [hours, minutes, seconds] = timeWithoutMs.split(":").map(Number);
 33→
 34→  return hours * 3600 + minutes * 60 + seconds + (ms ? Number(`0.${ms}`) : 0);
 35→}
 36→
 37→/**
 38→ * Parse SRT timestamp line (start --> end) to extract start and end times in seconds
 39→ * @param timingString SRT timing line (e.g., "00:01:23,456 --> 00:01:45,678")
 40→ * @returns Object with start and end times in seconds, or null if parsing fails
 41→ */
 42→export function parseSrtTiming(
 43→  timingString: string
 44→): { startTimeSeconds: number; endTimeSeconds: number } | null {
 45→  const parts = timingString.split(" --> ");
 46→  if (parts.length !== 2) {
 47→    return null;
 48→  }
 49→
 50→  return {
 51→    startTimeSeconds: timestampToSeconds(parts[0]),
 52→    endTimeSeconds: timestampToSeconds(parts[1]),
 53→  };
 54→}
 55→
 56→/**
 57→ * Format a start and end time in seconds to a SRT timing line
 58→ * @param startTimeSeconds Start time in seconds
 59→ * @param endTimeSeconds End time in seconds
 60→ * @returns SRT timing line (e.g., "00:01:23,456 --> 00:01:45,678")
 61→ */
 62→export function formatSrtTiming(
 63→  startTimeSeconds: number,
 64→  endTimeSeconds: number
 65→): string {
 66→  return `${secondsToTimestamp(startTimeSeconds)} --> ${secondsToTimestamp(
 67→    endTimeSeconds
 68→  )}`;
 69→}
