  7→/**
  8→ * Represents a parsed timestamp range from a transcript line.
  9→ */
 10→export interface ParsedTimestamp {
 11→  startTimeSeconds: number;
 12→  endTimeSeconds: number;
 13→  lineNumber: number; // Original line number for context
 14→}
 15→
 16→/**
 17→ * Parses a relative timestamp (mm:ss) to seconds.
 18→ */
 19→function parseMmSs(timeStr: string): number | null {
 20→  const parts = timeStr.split(":");
 21→  if (parts.length !== 2) return null;
 22→  const minutes = parseInt(parts[0], 10);
 23→  const seconds = parseInt(parts[1], 10);
 24→  if (isNaN(minutes) || isNaN(seconds)) return null;
 25→  return minutes * 60 + seconds;
 26→}
 27→
 28→/**
 29→ * More leniently parses raw transcript text to find timestamp ranges.
 30→ * Looks for the first occurrence of `mm:ss - mm:ss` on each line.
 31→ *
 32→ * @param rawTranscript The raw string output from the LLM.
 33→ * @returns An array of successfully parsed timestamp ranges.
 34→ */
 35→export function findTimestampRanges(rawTranscript: string): ParsedTimestamp[] {
 36→  const lines = rawTranscript.split("\n");
 37→  const parsedTimestamps: ParsedTimestamp[] = [];
 38→
 39→  // Regex to find "mm:ss - mm:ss" pattern anywhere, possibly preceded/followed by other chars
 40→  // It captures the two mm:ss parts.
 41→  const timeRangeRegex = /(\d{1,2}:\d{2})\s*-\s*(\d{1,2}:\d{2})/;
 42→
 43→  lines.forEach((line, index) => {
 44→    const match = line.match(timeRangeRegex);
 45→    if (match) {
 46→      const startTimeStr = match[1];
 47→      const endTimeStr = match[2];
 48→
 49→      const startTimeSeconds = parseMmSs(startTimeStr);
 50→      const endTimeSeconds = parseMmSs(endTimeStr);
 51→
 52→      // Basic sanity check on parsed times
 53→      if (
 54→        startTimeSeconds !== null &&
 55→        endTimeSeconds !== null &&
 56→        startTimeSeconds <= endTimeSeconds
 57→      ) {
 58→        parsedTimestamps.push({
 59→          startTimeSeconds,
 60→          endTimeSeconds,
 61→          lineNumber: index + 1,
 62→        });
 63→      } else {
 64→        // Log if parsing mm:ss failed even after regex match (unlikely but possible)
 65→        logger.debug(
 66→          `[Transcript Util] Malformed time components in line ${
 67→            index + 1
 68→          }: ${line.trim()}`
 69→        );
 70→      }
 71→    }
 72→    // We don't log lines that *don't* match anymore, as we only care about valid ranges now
 73→  });
 74→
 75→  return parsedTimestamps;
 76→}
 77→
 78→const MIN_SPAN_COVERAGE_RATIO = 0.75; // Require transcript span to be at least 75% of chunk duration
 79→
 80→/**
 81→ * Validates the parsed transcript timestamps based on duration relative to chunk size and optionally against a reference SRT.
 82→ *
 83→ * @param rawTranscript The raw transcript text.
 84→ * @param referenceSrtPath Optional path to the reference SRT chunk for span comparison.
 85→ * @param config The pipeline configuration object (must include chunkDuration).
 86→ * @param minTimestamps Minimum number of valid timestamp ranges required in the LLM transcript.
 87→ * @param allowedSpanDifferenceRatio Allowed fractional difference between LLM span and reference SRT span.
 88→ * @returns Object indicating if validation passed and the reason/details.
 89→ */
 90→export async function validateTranscriptTimestamps(
 91→  rawTranscript: string,
 92→  referenceSrtPath: string | undefined,
 93→  config: Pick<Config, "chunkDuration" | "disableTimingValidation">, // Expect chunkDuration
 94→  minTimestamps: number = 5,
 95→  allowedSpanDifferenceRatio: number = 0.1
 96→): Promise<{
 97→  isValid: boolean;
 98→  detectedLlmSpanSeconds: number | null;
 99→  referenceSrtSpanSeconds?: number | null;
100→  message: string;
101→}> {
102→  let validationMessage = "Validation checks passed.";
103→  let isValid = true;
104→  let detectedLlmSpanSeconds: number | null = null;
105→  let referenceSrtSpanSeconds: number | null = null;
106→
107→  if (!rawTranscript || rawTranscript.trim().length === 0) {
108→    return {
109→      isValid: false,
110→      detectedLlmSpanSeconds: null,
111→      message: "Transcript is empty.",
112→    };
113→  }
114→
115→  // --- Check LLM Transcript ---
116→  const parsedLlmTimestamps = findTimestampRanges(rawTranscript);
117→
118→  if (parsedLlmTimestamps.length < minTimestamps) {
119→    return {
120→      isValid: false,
121→      detectedLlmSpanSeconds: null,
122→      message: `Validation failed: Found only ${parsedLlmTimestamps.length} valid timestamp ranges in LLM output (minimum required: ${minTimestamps}).`,
123→    };
124→  }
125→
126→  parsedLlmTimestamps.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
127→  const firstLlmStartTime = parsedLlmTimestamps[0].startTimeSeconds;
128→  const lastLlmEndTime = Math.max(
129→    ...parsedLlmTimestamps.map((ts) => ts.endTimeSeconds)
130→  );
131→  detectedLlmSpanSeconds = lastLlmEndTime - firstLlmStartTime;
132→
133→  // 1. Check minimum duration relative to chunk duration
134→  const requiredMinSpanSeconds = config.chunkDuration * MIN_SPAN_COVERAGE_RATIO;
135→  if (detectedLlmSpanSeconds < requiredMinSpanSeconds) {
136→    return {
137→      isValid: false,
138→      detectedLlmSpanSeconds,
139→      message: `Validation failed: LLM transcript time span (${detectedLlmSpanSeconds.toFixed(
140→        1
141→      )}s) is less than minimum required (${requiredMinSpanSeconds.toFixed(
142→        1
143→      )}s, ${MIN_SPAN_COVERAGE_RATIO * 100}% of chunk duration ${
144→        config.chunkDuration
145→      }s).`,
146→    };
147→  }
148→
149→  // --- Check Against Reference SRT (if provided) ---
150→  if (referenceSrtPath && existsSync(referenceSrtPath)) {
151→    const referenceEntries = await parseSrtFile(referenceSrtPath);
152→    if (referenceEntries && referenceEntries.length > 0) {
153→      referenceSrtSpanSeconds = calculateSrtTimeSpan(referenceEntries);
154→
155→      if (referenceSrtSpanSeconds > 1.0) {
156→        const lowerBound =
157→          referenceSrtSpanSeconds * (1 - allowedSpanDifferenceRatio);
158→
159→        // Check only if LLM span is significantly SHORTER than reference
160→        if (detectedLlmSpanSeconds < lowerBound) {
161→          isValid = false;
162→          // Update message to only mention lower bound
163→          validationMessage = `Validation failed: LLM transcript span (${detectedLlmSpanSeconds.toFixed(
164→            1
165→          )}s) is shorter than allowed lower bound (${lowerBound.toFixed(
166→            1
167→          )}s) based on reference SRT span (${referenceSrtSpanSeconds.toFixed(
168→            1
169→          )}s).`;
170→        } else {
171→          validationMessage += ` LLM span (${detectedLlmSpanSeconds.toFixed(
172→            1
173→          )}s) meets or exceeds minimum duration compared to reference span (${referenceSrtSpanSeconds.toFixed(
174→            1
175→          )}s).`;
176→        }
177→      } else {
178→        logger.warn(
179→          `[Validation] Reference SRT span (${referenceSrtSpanSeconds.toFixed(
180→            1
181→          )}s) is too short for meaningful comparison. Skipping span check.`
182→        );
183→        validationMessage += ` Reference SRT span (${referenceSrtSpanSeconds.toFixed(
184→          1
185→        )}s) too short to compare.`;
186→      }
187→    } else {
188→      logger.warn(
189→        `[Validation] Could not parse or found no entries in reference SRT: ${referenceSrtPath}. Skipping span check.`
190→      );
191→      validationMessage += ` Could not read reference SRT.`;
192→    }
193→  } else if (referenceSrtPath) {
194→    logger.warn(
195→      `[Validation] Reference SRT path provided but not found: ${referenceSrtPath}. Skipping span check.`
196→    );
197→    validationMessage += ` Reference SRT not found.`;
198→  } else {
199→    validationMessage += ` No reference SRT provided for comparison.`;
200→  }
201→
202→  return {
203→    isValid,
204→    detectedLlmSpanSeconds,
205→    referenceSrtSpanSeconds,
206→    message: validationMessage,
207→  };
208→}
209→
210→/**
211→ * Adjusts timestamps in a raw transcript string using a time offset.
212→ * Replaces relative `mm:ss - mm:ss` timestamps with absolute `HH:MM:SS,sss` timestamps.
213→ * Lines without valid timestamps are kept as is.
214→ *
215→ * @param rawTranscript The raw transcript text from the LLM.
216→ * @param offsetSeconds The starting time offset (in seconds) for this chunk.
217→ * @returns The transcript text with adjusted absolute timestamps.
218→ */
219→export function adjustTranscriptTimestamps(
220→  rawTranscript: string,
221→  offsetSeconds: number
222→): string {
223→  const lines = rawTranscript.split("\n");
224→  const adjustedLines: string[] = [];
225→
226→  // Regex to find "mm:ss - mm:ss" pattern, potentially with surrounding chars
227→  const timeRangeRegex = /(\d{1,2}:\d{2})\s*-\s*(\d{1,2}:\d{2})/;
228→
229→  for (const line of lines) {
230→    const match = line.match(timeRangeRegex);
231→
232→    if (match) {
233→      const startTimeStr = match[1];
234→      const endTimeStr = match[2];
235→      const startTimeRelativeSeconds = parseMmSs(startTimeStr);
236→      const endTimeRelativeSeconds = parseMmSs(endTimeStr);
237→
238→      if (
239→        startTimeRelativeSeconds !== null &&
240→        endTimeRelativeSeconds !== null &&
241→        startTimeRelativeSeconds <= endTimeRelativeSeconds
242→      ) {
243→        const adjustedStartTime = startTimeRelativeSeconds + offsetSeconds;
244→        const adjustedEndTime = endTimeRelativeSeconds + offsetSeconds;
245→
246→        // Format using the HH:MM:SS,sss utility
247→        const formattedStartTime = secondsToTimestamp(adjustedStartTime);
248→        const formattedEndTime = secondsToTimestamp(adjustedEndTime);
249→
250→        // Replace the original timestamp part with the new absolute one
251→        const newLine = line.replace(
252→          match[0],
253→          `${formattedStartTime} --> ${formattedEndTime}`
254→        );
255→        adjustedLines.push(newLine);
256→      } else {
257→        // Keep line as is if mm:ss parsing failed within the regex match
258→        adjustedLines.push(line);
259→      }
260→    } else {
261→      // Keep lines without the timestamp pattern as they are
262→      adjustedLines.push(line);
263→    }
264→  }
265→
266→  return adjustedLines.join("\n");
267→}
