 65→/**
 66→ * Create a media chunk using ffmpeg
 67→ * @param videoPath Source video path
 68→ * @param outputPath Output path for chunk
 69→ * @param startTime Start time in seconds
 70→ * @param endTime End time in seconds
 71→ * @param format Output format ('mp3' or 'mp4')
 72→ * @returns Promise resolving to true if successful, false if error
 73→ */
 74→export async function createMediaChunk(
 75→  videoPath: string,
 76→  outputPath: string,
 77→  startTime: number,
 78→  endTime: number,
 79→  format: "mp3" | "mp4"
 80→): Promise<boolean> {
 81→  return new Promise((resolve) => {
 82→    const duration = endTime - startTime;
 83→    const formattedStart = secondsToTimestamp(startTime).replace(",", ".");
 84→
 85→    // Basic args for both formats
 86→    const args = [
 87→      "-y", // Overwrite output files
 88→      "-i",
 89→      videoPath,
 90→      "-ss",
 91→      formattedStart,
 92→      "-t",
 93→      duration.toString(),
 94→    ];
 95→
 96→    // Format-specific settings
 97→    if (format === "mp3") {
 98→      args.push(
 99→        "-vn", // No video
100→        "-acodec",
101→        "libmp3lame",
102→        "-ar",
103→        "44100",
104→        "-ab",
105→        "192k",
106→        "-f",
107→        "mp3"
108→      );
109→    } else {
110→      args.push(
111→        "-c:v",
112→        "libx264", // Video codec
113→        "-crf",
114→        "28", // Quality (higher number = lower quality)
115→        "-preset",
116→        "fast",
117→        "-vf",
118→        "scale=640:360", // 360p
119→        "-c:a",
120→        "aac",
121→        "-b:a",
122→        "128k"
123→      );
124→    }
125→
126→    // Output path
127→    args.push(outputPath);
128→
129→    logger.debug(
130→      `Running ffmpeg to create ${format} chunk from ${formattedStart} to ${secondsToTimestamp(
131→        endTime
132→      ).replace(",", ".")}`
133→    );
134→    const ffmpeg = spawn("ffmpeg", args);
135→    let errorOutput = "";
136→
137→    ffmpeg.stderr.on("data", (data) => {
138→      // ffmpeg outputs progress info to stderr
139→      const msg = data.toString();
140→      logger.debug(`[ffmpeg stderr] ${msg.trim()}`); // Log ffmpeg stderr at debug level
141→
142→      // Only accumulate actual errors
143→      if (
144→        msg.includes("Error") ||
145→        msg.includes("error") ||
146→        msg.includes("failed") ||
147→        msg.includes("Cannot")
148→      ) {
149→        errorOutput += msg;
150→      }
151→    });
152→
153→    ffmpeg.on("close", (code) => {
154→      if (code !== 0) {
155→        logger.error(
156→          `ffmpeg exited with code ${code} for chunk ${outputPath}. Error: ${errorOutput}`
157→        );
158→        resolve(false);
159→        return;
160→      }
161→
162→      logger.debug(`Successfully created ${format} chunk: ${outputPath}`);
163→      resolve(true);
164→    });
165→  });
166→}
