  9→const MIN_TRANSCRIPT_LINES = 5;
 10→
 11→// Helper to generate language string for prompt
 12→function getLanguagePromptString(languages?: string[]): string {
 13→  if (!languages || languages.length === 0) {
 14→    // Default if none specified
 15→    return "in the original spoken language(s)";
 16→  }
 17→  if (languages.length === 1) {
 18→    return `in ${languages[0]}`;
 19→  }
 20→  // Format like "likely lang1, maybe some lang2 or lang3"
 21→  const lastLang = languages[languages.length - 1];
 22→  const initialLangs = languages.slice(0, -1).join(", ");
 23→  return `in the original spoken language(s) (likely ${initialLangs}, maybe some ${lastLang})`;
 24→}
