  1→import { GoogleGenAI } from "@google/genai";
  2→import type { Config, ChunkInfo } from "../types.js";
  3→import * as logger from "../utils/logger.js";
  4→import { calculateCost } from "../config/models.js";
  5→
  6→/**
  7→ * Result structure for Gemini calls, including tokens.
  8→ */
  9→export interface GeminiCallResult {
 10→  responseText: string | null;
 11→  inputTokens?: number;
 12→  outputTokens?: number;
 13→  totalTokens?: number;
 14→}
 15→
 16→/**
 17→ * Sends a prompt to a Gemini model using generateContent
 18→ * and returns the text response and token counts.
 19→ */
 20→export async function callGemini(
 21→  prompt: string,
 22→  config: Config,
 23→  chunk: ChunkInfo
 24→): Promise<GeminiCallResult | null> {
 25→  const apiKey = config.apiKeys.gemini;
 26→  if (!apiKey) {
 27→    logger.error(`[Chunk ${chunk.partNumber}] Missing Gemini API key.`);
 28→    return null;
 29→  }
 30→
 31→  const modelName = config.translationModel;
 32→  logger.info(
 33→    `[Chunk ${chunk.partNumber}] Calling Gemini model: ${modelName}...`
 34→  );
 35→
 36→  try {
 37→    const genAI = new GoogleGenAI({ apiKey });
 38→    const result = await genAI.models.generateContent({
 39→      model: modelName,
 40→      contents: [{ role: "user", parts: [{ text: prompt }] }],
 41→    });
 42→
 43→    // Get text from the first candidate's content
 44→    let text: string | null = null;
 45→    if (result.candidates?.[0]?.content?.parts?.[0]?.text) {
 46→      text = result.candidates[0].content.parts[0].text;
 47→    }
 48→
 49→    // Extract token counts from usageMetadata if available
 50→    const usageMetadata = result.usageMetadata;
 51→    const inputTokens = usageMetadata?.promptTokenCount;
 52→    const outputTokens = usageMetadata?.candidatesTokenCount;
 53→    const totalTokens = usageMetadata?.totalTokenCount;
 54→
 55→    // Calculate and log cost if tokens are available
 56→    if (inputTokens !== undefined && outputTokens !== undefined) {
 57→      const cost = calculateCost(modelName, inputTokens, outputTokens);
 58→
 59→      // Store tokens and cost for this attempt
 60→      if (!chunk.allTranslationAttempts) {
 61→        chunk.allTranslationAttempts = [];
 62→      }
 63→
 64→      chunk.allTranslationAttempts.push({
 65→        inputTokens,
 66→        outputTokens,
 67→        cost,
 68→      });
 69→
 70→      // Calculate total translation cost
 71→      chunk.totalTranslationCost = chunk.allTranslationAttempts.reduce(
 72→        (sum, attempt) => sum + attempt.cost,
 73→        0
 74→      );
 75→
 76→      // Set the current attempt's values (for backward compatibility)
 77→      chunk.llmTranslationInputTokens = inputTokens;
 78→      chunk.llmTranslationOutputTokens = outputTokens;
 79→      chunk.cost = cost;
 80→
 81→      // Calculate total cost
 82→      chunk.totalCost =
 83→        (chunk.totalTranscriptionCost || 0) + (chunk.totalTranslationCost || 0);
 84→
 85→      logger.debug(
 86→        `[Chunk ${chunk.partNumber}] Gemini Tokens - Input: ${
 87→          inputTokens ?? "N/A"
 88→        }, Output: ${outputTokens ?? "N/A"}, Total: ${
 89→          totalTokens ?? "N/A"
 90→        }, Estimated Cost: $${cost.toFixed(
 91→          6
 92→        )}, Total Translation Cost: $${chunk.totalTranslationCost.toFixed(6)}`
 93→      );
 94→    } else if (inputTokens !== undefined || outputTokens !== undefined) {
 95→      logger.debug(
 96→        `[Chunk ${chunk.partNumber}] Gemini Tokens - Input: ${
 97→          inputTokens ?? "N/A"
 98→        }, Output: ${outputTokens ?? "N/A"}, Total: ${totalTokens ?? "N/A"}`
 99→      );
100→    }
101→
102→    if (!text || text.trim().length === 0) {
103→      logger.warn(`[Chunk ${chunk.partNumber}] Gemini response was empty.`);
104→      // Return result object even if text is null, tokens might be present
105→      return { responseText: null, inputTokens, outputTokens, totalTokens };
106→    }
107→    logger.debug(
108→      `[Chunk ${chunk.partNumber}] Received Gemini response (Length: ${text.length}).`
109→    );
110→    return { responseText: text, inputTokens, outputTokens, totalTokens };
111→  } catch (error: any) {
112→    logger.error(
113→      `[Chunk ${chunk.partNumber}] Gemini API error: ${error.message || error}`
114→    );
115→    if (
116→      error.response?.candidates?.length &&
117→      error.response?.candidates[0]?.finishReason
118→    ) {
119→      logger.error(
120→        `[Chunk ${chunk.partNumber}] Gemini API Error Details: FinishReason=${
121→          error.response.candidates[0].finishReason
122→        }, SafetyRatings=${JSON.stringify(
123→          error.response.candidates[0].safetyRatings
124→        )}`
125→      );
126→    } else if (error.message?.includes("request failed")) {
127→      logger.error(
128→        `[Chunk ${chunk.partNumber}] Gemini API network/status error: ${error.message}`
129→      );
130→    }
131→    return null; // Fatal error
132→  }
133→}
