214→// --- Core Parsing Logic (Adapted) ---
215→
216→/**
217→ * Extracts subtitle data from a single <subline> block content.
218→ * Adapts output to ParsedTranslationEntry format.
219→ */
220→function extractSublineData(
221→  tagContent: string,
222→  sourceFormat: ParsedTranslationEntry["sourceFormat"],
223→  issuesList: ProcessingIssue[],
224→  contextInfo: {
225→    fullContent: string;
226→    tagStartIndex: number;
227→    sourceChunk: number;
228→    targetLanguages: string[];
229→  }
230→): Omit<ParsedTranslationEntry, "sourceFormat" | "sourceChunk"> | null {
231→  const initialContext = {
232→    ...contextInfo,
233→    searchStartIndex: contextInfo.tagStartIndex,
234→  };
235→  const number = extractNestedTagContent(
236→    tagContent,
237→    ["original_number", "number", "id"],
238→    issuesList,
239→    initialContext
240→  );
241→
242→  if (!number) {
243→    if (!/<\/?(?:original_number|number|id)/i.test(tagContent)) {
244→      addIssue(
245→        issuesList,
246→        {
247→          type: "NumberNotFound",
248→          severity: "error",
249→          message: "Missing <original_number> tag.",
250→          contextSnippet: tagContent,
251→        },
252→        contextInfo.tagStartIndex,
253→        contextInfo.fullContent
254→      );
255→    } else {
256→      addIssue(
257→        issuesList,
258→        {
259→          type: "ExtractionFailed",
260→          severity: "error",
261→          message:
262→            "Found potential <original_number> tag but failed to extract content.",
263→          contextSnippet: tagContent,
264→        },
265→        contextInfo.tagStartIndex,
266→        contextInfo.fullContent
267→      );
268→    }
269→    return null;
270→  }
271→
272→  const updatedContext = {
273→    ...contextInfo,
274→    currentId: number,
275→    searchStartIndex: contextInfo.tagStartIndex,
276→  };
277→
278→  const originalLine = extractNestedTagContent(
279→    tagContent,
280→    "original_line",
281→    issuesList,
282→    updatedContext
283→  );
284→  const timingValue = extractNestedTagContent(
285→    tagContent,
286→    ["original_timing", "timing"],
287→    issuesList,
288→    updatedContext
289→  );
290→
291→  const translations: Record<string, string | null> = {};
292→  let hasAnyTranslation = false;
293→  translations["english"] = extractNestedTagContent(
294→    tagContent,
295→    ["better_english_translation", "english_translation", "english"],
296→    issuesList,
297→    updatedContext
298→  );
299→  if (translations["english"] !== null) hasAnyTranslation = true;
300→  for (const lang of contextInfo.targetLanguages) {
301→    const safeLangTag = lang.toLowerCase().replace(/\s+/g, "_");
302→    translations[lang] = extractNestedTagContent(
303→      tagContent,
304→      `${safeLangTag}_translation`,
305→      issuesList,
306→      updatedContext
307→    );
308→    if (translations[lang] !== null) hasAnyTranslation = true;
309→  }
310→  if (!hasAnyTranslation) {
311→    addIssue(
312→      issuesList,
313→      {
314→        type: "TextNotFound",
315→        severity: "warning",
316→        subtitleId: number,
317→        message:
318→          "Found ID but failed to extract any English or target language translations.",
319→        contextSnippet: tagContent,
320→      },
321→      contextInfo.tagStartIndex,
322→      contextInfo.fullContent
323→    );
324→  }
325→
326→  let parsedStartTime: number | undefined = undefined;
327→  let parsedEndTime: number | undefined = undefined;
328→  if (timingValue) {
329→    try {
330→      const parts = timingValue.split(" --> ");
331→      if (parts.length === 2) {
332→        parsedStartTime = timeToSeconds(parts[0].trim());
333→        parsedEndTime = timeToSeconds(parts[1].trim());
334→        if (!isValidTiming(parsedStartTime, parsedEndTime)) {
335→          addIssue(
336→            issuesList,
337→            {
338→              type: "InvalidTimingValue",
339→              severity: "warning",
340→              subtitleId: number,
341→              message: `Invalid timing values: ${timingValue}`,
342→              contextSnippet: timingValue,
343→            },
344→            contextInfo.tagStartIndex,
345→            contextInfo.fullContent
346→          );
347→          parsedStartTime = undefined;
348→          parsedEndTime = undefined;
349→        }
350→      } else {
351→        addIssue(
352→          issuesList,
353→          {
354→            type: "InvalidTimingFormat",
355→            severity: "warning",
356→            subtitleId: number,
357→            message: `Invalid timing format (expected -->): ${timingValue}`,
358→            contextSnippet: timingValue,
359→          },
360→          contextInfo.tagStartIndex,
361→          contextInfo.fullContent
362→        );
363→      }
364→    } catch (e: any) {
365→      addIssue(
366→        issuesList,
367→        {
368→          type: "InvalidTimingFormat",
369→          severity: "warning",
370→          subtitleId: number,
371→          message: `Failed to parse timing string components: ${timingValue} - ${e.message}`,
372→          contextSnippet: timingValue,
373→        },
374→        contextInfo.tagStartIndex,
375→        contextInfo.fullContent
376→      );
377→    }
378→  }
379→
380→  return {
381→    originalId: number,
382→    originalLine: originalLine ?? undefined,
383→    originalTiming: timingValue ?? undefined,
384→    parsedStartTimeSeconds: parsedStartTime,
385→    parsedEndTimeSeconds: parsedEndTime,
386→    translations,
387→  };
388→}
