390→/**
391→ * Main parsing function for the LLM response content.
392→ * @param llmResponseContent The raw text response from the translation LLM.
393→ * @param sourceChunkNumber The part number this response corresponds to.
394→ * @param targetLanguages The list of target languages expected.
395→ * @returns An object containing the list of parsed entries and any issues found.
396→ */
397→export function parseTranslationResponse(
398→  llmResponseContent: string,
399→  sourceChunkNumber: number,
400→  targetLanguages: string[]
401→): { entries: ParsedTranslationEntry[]; issues: ProcessingIssue[] } {
402→  const entries: ParsedTranslationEntry[] = [];
403→  const issuesList: ProcessingIssue[] = [];
404→  const foundIds = new Set<string>();
405→  const processedRanges: { start: number; end: number }[] = [];
406→
407→  let summary = {
408→    totalEntriesAttempted: 0,
409→    successfullyParsed: 0,
410→    markdownBlocksProcessed: 0,
411→    directTagsProcessed: 0,
412→    errors: 0,
413→    warnings: 0,
414→  };
415→
416→  const markdownBlockRegex = /```(?:xml)?\s*\n?([\s\S]*?)\n?```/g;
417→  let markdownMatch;
418→  while (
419→    (markdownMatch = markdownBlockRegex.exec(llmResponseContent)) !== null
420→  ) {
421→    summary.markdownBlocksProcessed++;
422→    const blockContent = markdownMatch[1].trim();
423→    const blockStartIndex =
424→      markdownMatch.index + markdownMatch[0].indexOf(blockContent);
425→    processedRanges.push({
426→      start: markdownMatch.index,
427→      end: markdownMatch.index + markdownMatch[0].length,
428→    });
429→
430→    if (!blockContent) {
431→      addIssue(
432→        issuesList,
433→        {
434→          type: "MarkdownBlockEmptyOrInvalid",
435→          severity: "warning",
436→          message: "Found empty markdown block.",
437→          contextSnippet: markdownMatch[0],
438→        },
439→        markdownMatch.index,
440→        llmResponseContent
441→      );
442→      continue;
443→    }
444→
445→    const sublineRegex = /<subline>([\s\S]*?)<\/subline>/gi;
446→    let sublineMatch;
447→    let foundSubTagInBlock = false;
448→    while ((sublineMatch = sublineRegex.exec(blockContent)) !== null) {
449→      foundSubTagInBlock = true;
450→      summary.totalEntriesAttempted++;
451→      const sublineContent = sublineMatch[1];
452→      const sublineStartIndex =
453→        blockStartIndex +
454→        sublineMatch.index +
455→        sublineMatch[0].indexOf(sublineContent);
456→
457→      const contextInfo = {
458→        fullContent: llmResponseContent,
459→        tagStartIndex: sublineStartIndex,
460→        sourceChunk: sourceChunkNumber,
461→        targetLanguages,
462→      };
463→      const extracted = extractSublineData(
464→        sublineContent,
465→        "markdown",
466→        issuesList,
467→        contextInfo
468→      );
469→
470→      if (extracted) {
471→        if (foundIds.has(extracted.originalId)) {
472→          addIssue(
473→            issuesList,
474→            {
475→              type: "DuplicateId",
476→              severity: "warning",
477→              subtitleId: extracted.originalId,
478→              message: `Duplicate ID found (markdown).`,
479→            },
480→            sublineStartIndex,
481→            llmResponseContent
482→          );
483→        } else {
484→          foundIds.add(extracted.originalId);
485→          entries.push({
486→            ...extracted,
487→            sourceChunk: sourceChunkNumber,
488→            sourceFormat: "markdown",
489→          });
490→          summary.successfullyParsed++;
491→        }
492→      }
493→    }
494→    if (!foundSubTagInBlock && blockContent.length > 0) {
495→      addIssue(
496→        issuesList,
497→        {
498→          type: "AmbiguousStructure",
499→          severity: "warning",
500→          message: "Markdown block found but contained no <subline> tags.",
501→          contextSnippet: blockContent,
502→        },
503→        blockStartIndex,
504→        llmResponseContent
505→      );
506→    }
507→  }
508→
509→  const directSublineRegex = /<subline>([\s\S]*?)<\/subline>/gi;
510→  let directMatch;
511→  while ((directMatch = directSublineRegex.exec(llmResponseContent)) !== null) {
512→    const matchStartIndex = directMatch.index;
513→    if (
514→      processedRanges.some(
515→        (range) => matchStartIndex >= range.start && matchStartIndex < range.end
516→      )
517→    ) {
518→      continue;
519→    }
520→    summary.totalEntriesAttempted++;
521→    summary.directTagsProcessed++;
522→    const sublineContent = directMatch[1];
523→    const sublineStartIndex =
524→      matchStartIndex + directMatch[0].indexOf(sublineContent);
525→    const contextInfo = {
526→      fullContent: llmResponseContent,
527→      tagStartIndex: sublineStartIndex,
528→      sourceChunk: sourceChunkNumber,
529→      targetLanguages,
530→    };
531→    const extracted = extractSublineData(
532→      sublineContent,
533→      "direct_tag",
534→      issuesList,
535→      contextInfo
536→    );
537→
538→    if (extracted) {
539→      if (foundIds.has(extracted.originalId)) {
540→        addIssue(
541→          issuesList,
542→          {
543→            type: "DuplicateId",
544→            severity: "warning",
545→            subtitleId: extracted.originalId,
546→            message: `Duplicate ID found (direct tag).`,
547→          },
548→          sublineStartIndex,
549→          llmResponseContent
550→        );
551→      } else {
552→        foundIds.add(extracted.originalId);
553→        entries.push({
554→          ...extracted,
555→          sourceChunk: sourceChunkNumber,
556→          sourceFormat: "direct_tag",
557→        });
558→        summary.successfullyParsed++;
559→      }
560→    }
561→  }
562→
563→  entries.sort((a, b) => {
564→    const numA = parseInt(a.originalId, 10);
565→    const numB = parseInt(b.originalId, 10);
566→    if (isNaN(numA)) return 1;
567→    if (isNaN(numB)) return -1;
568→    return numA - numB;
569→  });
570→
571→  summary.errors = issuesList.filter((i) => i.severity === "error").length;
572→  summary.warnings = issuesList.filter((i) => i.severity === "warning").length;
573→
574→  logger.debug(
575→    `[Chunk ${sourceChunkNumber}] Parsing complete. Found: ${summary.successfullyParsed}, Errors: ${summary.errors}, Warnings: ${summary.warnings}`
576→  );
577→
578→  return { entries, issues: issuesList };
579→}
