16→ * @param markFallback Whether to visually mark fallbacks.
17→ * @returns Formatted text block for the SRT entry.
18→ */
19→function applyColorsAndFormatText(
20→  translations: Record<string, string | null>,
21→  targetLanguage: string, // The actual key, e.g., 'Korean'
22→  englishColor: string = DEFAULT_ENGLISH_COLOR,
23→  targetColor: string = DEFAULT_TARGET_COLOR,
24→  isFallback: boolean = false,
25→  markFallback: boolean = true
26→): string {
27→  let outputText = "";
28→  const englishText = translations["english"];
29→  const targetText = translations[targetLanguage];
30→
31→  if (englishText) {
32→    if (markFallback && isFallback) {
33→      outputText += `<font color="#${englishColor}">[Original] ${englishText}</font>`;
34→    } else {
35→      outputText += `<font color="#${englishColor}">${englishText}</font>`;
36→    }
37→  }
38→
39→  if (targetText) {
40→    if (outputText) {
41→      outputText += "\n"; // Add newline if English text was present
42→    }
43→    outputText += `<font color="#${targetColor}">${targetText}</font>`;
44→  }
45→
46→  // If both are somehow null/empty (should be filtered earlier ideally), return a placeholder
47→  if (!outputText) {
48→    return "(Text unavailable)";
49→  }
50→
51→  return outputText;
52→}
