 64→    const data = await readJsonFromFile<ParsedTranslationEntry[]>(filePath);
 65→    if (data) {
 66→      allParsed = allParsed.concat(data);
 67→    } else {
 68→      logger.warn(`Failed to load or parse data from ${file}.`);
 69→    }
 70→  }
 71→  logger.info(
 72→    `Loaded ${allParsed.length} parsed entries from ${jsonFiles.length} files.`
 73→  );
 74→  return allParsed;
 75→}
 76→
 77→/** Merges translations, selects timing, handles chunk overlaps and fallbacks. */
 78→async function mergeTranslations(
 79→  allParsedEntries: ParsedTranslationEntry[],
 80→  originalSrtPath: string | undefined,
 81→  config: Pick<
 82→    Config,
 83→    "useResponseTimings" | "targetLanguages" | "inputOffsetSeconds"
 84→  >
 85→): Promise<{
 86→  mergedEntries: Omit<FinalSubtitleEntry, "finalId">[];
 87→  issues: ProcessingIssue[];
 88→}> {
 89→  const issues: ProcessingIssue[] = [];
 90→  const translationsById = new Map<string, ParsedTranslationEntry>();
 91→
 92→  // Resolve chunk overlaps - keep entry from the latest chunk
 93→  allParsedEntries.forEach((entry) => {
 94→    const existing = translationsById.get(entry.originalId);
 95→    if (!existing || entry.sourceChunk >= existing.sourceChunk) {
 96→      translationsById.set(entry.originalId, entry);
 97→    }
 98→  });
 99→  logger.debug(
100→    `Resolved chunk overlaps. Kept ${translationsById.size} unique entries.`
101→  );
102→
103→  // Load original SRT, passing the input offset
104→  let originalSrtMap: Map<string, SrtEntry> | null = null;
105→  const inputOffset = config.inputOffsetSeconds ?? 0;
106→  if (originalSrtPath && existsSync(originalSrtPath)) {
107→    // Pass offset to parser
108→    const srtEntries = await parseSrtFile(originalSrtPath, inputOffset);
109→    if (srtEntries) {
110→      originalSrtMap = new Map(srtEntries.map((e) => [e.id.toString(), e]));
111→      logger.debug(
112→        `Loaded ${originalSrtMap.size} original SRT entries (offset: ${inputOffset}s).`
113→      );
114→    } else {
115→      logger.warn(`Failed to parse original SRT: ${originalSrtPath}`);
116→      // Don't push issue here, handled below if needed
117→    }
118→  }
119→  if (!originalSrtMap) {
120→    logger.warn(
121→      "Original SRT not found or unreadable. Fallback timing/text unavailable."
122→    );
123→    if (!config.useResponseTimings) {
124→      logger.error(
125→        "Original SRT timings requested but file unavailable! Cannot proceed."
126→      );
127→      issues.push({
128→        type: "MergeError",
129→        severity: "error",
130→        message: "Original SRT required for timing but not found/readable.",
131→      });
132→      return { mergedEntries: [], issues };
133→    }
134→  }
135→
136→  const mergedEntries: Omit<FinalSubtitleEntry, "finalId">[] = [];
137→  const targetLanguage = config.targetLanguages[0]; // Assume single target language
138→
139→  for (const entry of translationsById.values()) {
140→    let startTime: number | undefined = undefined;
141→    let endTime: number | undefined = undefined;
142→    let timingSource: FinalSubtitleEntry["timingSource"] = "llm";
143→    let isFallback = false;
144→
145→    // Filter based on skip marker
146→    if (
147→      entry.translations["english"] === SKIP_MARKER ||
148→      entry.translations[targetLanguage] === SKIP_MARKER
149→    ) {
150→      logger.debug(`Skipping entry ID ${entry.originalId} due to SKIP_MARKER.`);
151→      continue;
152→    }
153→
154→    // Determine timing source
155→    if (
156→      config.useResponseTimings &&
157→      entry.parsedStartTimeSeconds !== undefined &&
158→      entry.parsedEndTimeSeconds !== undefined
159→    ) {
160→      startTime = entry.parsedStartTimeSeconds;
161→      endTime = entry.parsedEndTimeSeconds;
162→      timingSource = "llm";
163→    } else {
164→      const originalSrtEntry = originalSrtMap?.get(entry.originalId);
165→      if (originalSrtEntry) {
166→        startTime = originalSrtEntry.startTimeSeconds;
167→        endTime = originalSrtEntry.endTimeSeconds;
168→        timingSource = "original";
169→      } else {
170→        // If original timing requested but not found, OR response timing requested but invalid/missing
171→        if (!config.useResponseTimings) {
172→          issues.push({
173→            type: "MergeError",
174→            severity: "warning",
175→            subtitleId: entry.originalId,
176→            message: `Original SRT timing requested but entry ID not found in original SRT. Skipping entry.`,
177→          });
178→          continue; // Skip if timing is missing and was required
179→        } else {
180→          // Attempt to use LLM timing even if invalid? No, skip if no valid timing source found.
181→          issues.push({
182→            type: "MergeError",
183→            severity: "warning",
184→            subtitleId: entry.originalId,
185→            message: `LLM timing requested but entry had no valid timing. Original SRT entry also missing. Skipping entry.`,
186→          });
187→          continue;
188→        }
189→      }
190→    }
191→
192→    // Determine fallback status
193→    const originalSrtEntry = originalSrtMap?.get(entry.originalId);
194→    isFallback = !entry.translations["english"] && !!originalSrtEntry?.text;
195→    const finalTranslations = { ...entry.translations };
196→    if (isFallback && originalSrtEntry) {
197→      finalTranslations["english"] = originalSrtEntry.text; // Use original text for fallback
198→    }
199→
200→    mergedEntries.push({
201→      originalId: entry.originalId,
202→      startTimeSeconds: startTime,
203→      endTimeSeconds: endTime,
204→      translations: finalTranslations,
205→      isFallback,
206→      timingSource,
207→    });
208→  }
209→
210→  logger.info(`Merged ${mergedEntries.length} entries.`);
211→  return { mergedEntries, issues };
212→}
213→
214→/** Fixes overlaps and clamps durations */
215→function fixAndClampTimings(
216→  entries: Omit<FinalSubtitleEntry, "finalId">[]
217→): Omit<FinalSubtitleEntry, "finalId">[] {
218→  if (entries.length === 0) return [];
219→
220→  logger.debug("Sorting entries by start time for overlap check...");
221→  entries.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
222→
223→  let changed = true;
224→  let pass = 0;
225→  const MAX_PASSES = 10; // Safety break for infinite loops
226→  logger.info("Starting overlap correction pass...");
227→
228→  while (changed && pass < MAX_PASSES) {
229→    changed = false;
230→    pass++;
231→    logger.debug(`Overlap correction pass ${pass}...`);
232→    let overlapsFixedThisPass = 0;
233→
234→    for (let i = 0; i < entries.length - 1; i++) {
235→      const current = entries[i];
236→      const next = entries[i + 1];
237→
238→      if (current.endTimeSeconds > next.startTimeSeconds) {
239→        // overlap = current end - next start
240→        const overlapDuration = current.endTimeSeconds - next.startTimeSeconds;
241→        // Calculate potential new end time by shortening current
242→        const targetEndTime = next.startTimeSeconds - OVERLAP_GAP_S;
243→        // Calculate potential new duration if shortened
244→        const newDuration = targetEndTime - current.startTimeSeconds;
245→
246→        // Logic from user: newEndTime = min(current.startTime + maxDuration, next.startTime - gap)
247→        const maxEndTimeFromDuration =
248→          current.startTimeSeconds + MAX_SUB_DURATION;
249→        const potentialNewEndTime = Math.min(
250→          maxEndTimeFromDuration,
251→          targetEndTime
252→        );
253→
254→        // Check if new end time respects minimum duration
255→        if (
256→          potentialNewEndTime - current.startTimeSeconds >=
257→          MIN_SUB_DURATION
258→        ) {
259→          if (current.endTimeSeconds !== potentialNewEndTime) {
260→            // Only log if change occurs
261→            logger.debug(
262→              `  Fixing overlap: ID ${
263→                current.originalId
264→              } (${current.endTimeSeconds.toFixed(
265→                3
266→              )}s) adjusted to ${potentialNewEndTime.toFixed(3)}s (before ID ${
267→                next.originalId
268→              } starting at ${next.startTimeSeconds.toFixed(3)}s).`
269→            );
270→            current.endTimeSeconds = potentialNewEndTime;
271→            changed = true;
272→            overlapsFixedThisPass++;
273→          }
274→        } else {
275→          // Cannot shorten current, log a warning
276→          logger.warn(
277→            `  Overlap detected: ID ${
278→              current.originalId
279→            } (${current.endTimeSeconds.toFixed(3)}s) overlaps ID ${
280→              next.originalId
281→            } (${next.startTimeSeconds.toFixed(
282→              3
283→            )}s) by ${overlapDuration.toFixed(3)}s. Cannot shorten ID ${
284→              current.originalId
285→            } without violating min duration (${MIN_SUB_DURATION}s). Leaving overlap.`
286→          );
287→          // Consider alternative strategies like shifting next subtitle if this becomes a major issue
288→        }
289→      }
290→    }
291→    logger.debug(`Pass ${pass} fixed ${overlapsFixedThisPass} overlaps.`);
292→  }
293→  if (pass >= MAX_PASSES) {
294→    logger.warn(
295→      "Reached maximum overlap correction passes. Some overlaps might remain."
296→    );
297→  }
298→  logger.info(`Overlap correction finished after ${pass} passes.`);
299→
300→  // --- Duration Clamping ---
301→  logger.info("Clamping subtitle durations...");
302→  let clampedShort = 0;
303→  let clampedLong = 0;
304→  for (const entry of entries) {
305→    const duration = entry.endTimeSeconds - entry.startTimeSeconds;
306→    let changed = false;
307→    if (duration < MIN_SUB_DURATION) {
308→      entry.endTimeSeconds = entry.startTimeSeconds + MIN_SUB_DURATION;
309→      clampedShort++;
310→      changed = true;
311→    } else if (duration > MAX_SUB_DURATION) {
312→      entry.endTimeSeconds = entry.startTimeSeconds + MAX_SUB_DURATION;
313→      clampedLong++;
314→      changed = true;
315→    }
316→    // Note: Clamping might re-introduce overlaps. A final overlap check pass could be added if needed.
317→    if (changed && clampedShort + clampedLong < 10) {
318→      // Log first few clamps
319→      logger.debug(
320→        `  Clamped ID ${entry.originalId}: New duration ${(
321→          entry.endTimeSeconds - entry.startTimeSeconds
322→        ).toFixed(3)}s`
323→      );
324→    }
325→  }
326→  logger.info(
327→    `Duration clamping: Fixed ${clampedShort} too short, ${clampedLong} too long.`
328→  );
329→
330→  // Re-sort by original ID for final output sequence
331→  logger.debug("Sorting entries by original ID...");
332→  entries.sort((a, b) => {
333→    const numA = parseInt(a.originalId, 10);
334→    const numB = parseInt(b.originalId, 10);
335→    if (isNaN(numA)) return 1;
336→    if (isNaN(numB)) return -1;
337→    return numA - numB;
338→  });
339→
340→  return entries;
341→}
342→
343→/**
344→ * Main finalizer function for the pipeline.
345→ */
346→export async function finalize(
347→  chunks: ChunkInfo[],
348→  config: Config
349→): Promise<{ finalSrtPath?: string; issues: ProcessingIssue[] }> {
350→  const issues: ProcessingIssue[] = [];
351→  const parsedDataDir = join(config.intermediateDir, "parsed_data");
352→  const finalOutputDir = config.outputDir;
353→  ensureDir(finalOutputDir);
354→
355→  // TODO: Add checkChunkContinuity logic here if needed
356→  const totalChunks = Math.max(...chunks.map((c) => c.partNumber)); // Rough estimate
357→
358→  // Load all parsed data
359→  const allParsedEntries = await loadParsedData(parsedDataDir, totalChunks);
360→  if (allParsedEntries.length === 0) {
361→    issues.push({
362→      type: "MergeError",
363→      severity: "error",
364→      message: "No parsed data found to generate final SRT.",
365→    });
366→    return { issues };
367→  }
368→
369→  // Merge translations and select timings
370→  const mergeResult = await mergeTranslations(
371→    allParsedEntries,
372→    config.srtPath,
373→    config
374→  );
375→  issues.push(...mergeResult.issues);
376→  if (
377→    mergeResult.mergedEntries.length === 0 &&
378→    issues.some((i) => i.severity === "error")
379→  ) {
380→    logger.error("Failed to merge any entries due to errors.");
381→    return { issues }; // Return early if merge failed critically
382→  }
383→  let finalSubtitleData = mergeResult.mergedEntries;
384→
385→  // Fix overlaps and clamp durations
386→  finalSubtitleData = fixAndClampTimings(finalSubtitleData);
387→
388→  // Generate final SRT content
389→  logger.info("Generating final SRT string...");
390→  let srtContent = "";
391→  const targetLanguage = config.targetLanguages[0]; // Assume single target
392→  const outputOffset = config.outputOffsetSeconds ?? 0; // Get offset or default to 0
393→
394→  if (outputOffset !== 0) {
395→    logger.info(`Applying output offset of ${outputOffset} seconds.`);
396→  }
397→
398→  finalSubtitleData.forEach((entry, index) => {
399→    // Apply offset before formatting
400→    const finalStartTime = entry.startTimeSeconds + outputOffset;
401→    const finalEndTime = entry.endTimeSeconds + outputOffset;
402→
403→    // Prevent negative timestamps after offset
404→    if (finalStartTime < 0 || finalEndTime < 0) {
405→      logger.warn(
406→        `[ID ${entry.originalId}] Skipping entry due to negative timestamp after applying offset ${outputOffset}s.`
407→      );
408→      return; // Skip this entry
409→    }
410→
411→    const finalEntry: FinalSubtitleEntry = {
412→      ...entry,
413→      finalId: index + 1, // Renumber sequentially
414→      markFallback: config.markFallbacks,
415→      // Use the offset-adjusted times
416→      startTimeSeconds: finalStartTime,
417→      endTimeSeconds: finalEndTime,
418→    };
419→    srtContent += formatSrtEntry(finalEntry, targetLanguage, config);
420→  });
421→
422→  // Determine final filename
423→  const baseName = config.videoPath
424→    ? parsePath(config.videoPath).name
425→    : "output";
426→  const langSuffix = targetLanguage.toLowerCase();
427→  const finalSrtFilename = `${baseName}.bilingual.${langSuffix}.srt`;
428→  const finalSrtPath = join(finalOutputDir, finalSrtFilename);
429→
430→  // Write final file
431→  const writeSuccess = await writeToFile(finalSrtPath, srtContent);
432→  if (writeSuccess) {
433→    logger.success(`Final bilingual SRT saved to: ${finalSrtPath}`);
434→    return { finalSrtPath, issues };
435→  } else {
436→    issues.push({
437→      type: "FormatError",
438→      severity: "error",
439→      message: `Failed to write final SRT file to ${finalSrtPath}`,
440→    });
441→    return { issues };
442→  }
443→}
444→
445→// --- CLI Logic ---
446→
447→interface FinalizerCliOptions {
448→  intermediateDir: string;
449→  originalSrt: string;
450→  outputDir: string;
451→  outputFilename?: string;
452→  targetLanguage: string; // Single target language
453→  useResponseTimings?: boolean;
454→  markFallbacks?: boolean;
455→  logLevel?: string;
456→  outputOffset?: number;
457→  inputOffset?: number;
458→}
459→
460→async function cliMain() {
461→  const program = new Command();
462→  program
463→    .name("subtitle-finalizer")
464→    .description(
465→      "Merges parsed translations, fixes timings, and formats final bilingual SRT."
466→    )
467→    .requiredOption(
468→      "-i, --intermediate-dir <path>",
469→      "Path to the intermediate directory containing parsed_data/"
470→    )
471→    .requiredOption(
472→      "-s, --original-srt <path>",
473→      "Path to the original full SRT file"
474→    )
475→    .option(
476→      "-o, --output-dir <path>",
477→      "Directory for final output SRT",
478→      "./output"
479→    )
480→    .option(
481→      "-f, --output-filename <name>",
482→      "Filename for the final SRT (defaults based on video name)"
483→    )
484→    .requiredOption(
485→      "-l, --language <lang>",
486→      "The target language used in translations (e.g., Korean)"
487→    )
488→    .option(
489→      "--use-response-timings",
490→      "Use timings parsed from LLM response instead of original SRT",
491→      false
492→    )
493→    .option(
494→      "--mark-fallbacks",
495→      "Add [Original] marker to fallback subtitles",
496→      true
497→    )
498→    .option("--log-file <path>", "Path to log file")
499→    .option("--log-level <level>", "Log level", "info")
500→    .option(
501→      "--output-offset <seconds>",
502→      "Add offset (in seconds, can be negative) to final subtitle timings"
503→    )
504→    .option(
505→      "--input-offset <seconds>",
506→      "Apply offset (in seconds, can be negative) to input SRT timings"
507→    )
508→    .parse(process.argv);
509→
510→  const opts = program.opts();
511→  logger.configureLogger({
512→    logToFile: !!opts.logFile,
513→    logFilePath: opts.logFile,
514→    consoleLogLevel: opts.logLevel || "info",
515→  });
516→
517→  // Parse colors
518→  let engColor: string | undefined;
519→  let tgtColor: string | undefined;
520→  if (opts.colors) {
521→    [engColor, tgtColor] = opts.colors.split(",").map((c: string) => c.trim());
522→  }
523→
524→  const cliOptions: FinalizerCliOptions = {
525→    intermediateDir: opts.intermediateDir,
526→    originalSrt: opts.originalSrt,
527→    outputDir: opts.outputDir,
528→    outputFilename: opts.outputFilename,
529→    targetLanguage: opts.language.trim(),
530→    useResponseTimings: opts.useResponseTimings || false,
531→    markFallbacks: opts.markFallbacks !== undefined ? opts.markFallbacks : true,
532→    logLevel: opts.logLevel,
533→    outputOffset: opts.outputOffset ? parseFloat(opts.outputOffset) : undefined,
534→    inputOffset: opts.inputOffset ? parseFloat(opts.inputOffset) : undefined,
535→  };
536→
537→  // Build minimal config for finalize function
538→  const config: Partial<Config> = {
539→    intermediateDir: cliOptions.intermediateDir,
540→    srtPath: cliOptions.originalSrt,
541→    outputDir: cliOptions.outputDir,
542→    targetLanguages: [cliOptions.targetLanguage],
543→    useResponseTimings: cliOptions.useResponseTimings,
544→    markFallbacks: cliOptions.markFallbacks,
545→    subtitleColorEnglish: engColor,
546→    subtitleColorTarget: tgtColor,
547→    outputOffsetSeconds: cliOptions.outputOffset ?? 0,
548→    inputOffsetSeconds: cliOptions.inputOffset ?? 0,
549→    videoPath: cliOptions.outputFilename,
550→  };
551→
552→  try {
553→    logger.info(chalk.blueBright("--- Starting Subtitle Finalization ---"));
554→
555→    // Estimate chunk count (less critical for standalone, maybe scan parsed_data dir?)
556→    let estChunkCount = 1;
557→    const parsedDataDir = join(config.intermediateDir!, "parsed_data");
558→    if (existsSync(parsedDataDir)) {
559→      estChunkCount =
560→        (await readdir(parsedDataDir)).filter((f) => f.endsWith("_parsed.json"))
561→          .length || 1;
562→    }
563→
564→    // Create a dummy chunks array for finalize call signature
565→    const dummyChunks: ChunkInfo[] = Array.from(
566→      { length: estChunkCount },
567→      (_, i) => ({
568→        partNumber: i + 1,
569→        status: "completed", // Assume completed for this stage
570→        startTimeSeconds: 0,
571→        endTimeSeconds: 0,
572→      })
573→    );
574→
575→    const { finalSrtPath, issues } = await finalize(
576→      dummyChunks,
577→      config as Config
578→    );
579→
580→    // --- Final Reporting ---
581→    logger.info(chalk.blueBright("--- Finalizer Report ---"));
582→    const errorCount = issues.filter((i) => i.severity === "error").length;
583→    const warningCount = issues.filter((i) => i.severity === "warning").length;
584→
585→    let reportContent = "";
586→    if (finalSrtPath) {
587→      reportContent += `${chalk.green(
588→        "Success:"
589→      )} Final SRT generated at ${finalSrtPath}\n`;
590→    } else {
591→      reportContent += `${chalk.red(
592→        "Failure:"
593→      )} Could not generate final SRT file.\n`;
594→    }
595→    reportContent += `${chalk.red("Errors Found:")}       ${errorCount}\n`;
596→    reportContent += `${chalk.yellow("Warnings Found:")}     ${warningCount}\n`;
597→    if (issues.length > 0) {
598→      reportContent += `\n${chalk.yellowBright("Issues Encountered:")} (${
599→        issues.length
600→      })\n`;
601→      issues.sort(
602→        (a, b) =>
603→          (a.chunkPart ?? 0) - (b.chunkPart ?? 0) ||
604→          (a.subtitleId ? parseInt(a.subtitleId.toString()) : Infinity) -
605→            (b.subtitleId ? parseInt(b.subtitleId.toString()) : Infinity)
606→      );
607→      issues.forEach((issue) => {
608→        const prefix =
609→          issue.severity === "error"
610→            ? chalk.red("ERROR")
611→            : chalk.yellow("WARN");
612→        reportContent += `- ${prefix}: [Chunk ${
613→          issue.chunkPart ?? "N/A"
614→        }] [ID ${issue.subtitleId || "N/A"}] ${issue.message}\n`;
615→      });
616→    }
617→    console.log(
618→      boxen(reportContent, {
619→        title: "Finalizer Summary",
620→        padding: 1,
621→        margin: 1,
622→        borderStyle: "round",
623→        borderColor: "green",
624→      })
625→    );
626→
627→    process.exit(errorCount > 0 ? 1 : 0);
628→  } catch (err: any) {
629→    logger.error(`Fatal finalizer error: ${err.message || err}`, err.stack);
630→    console.error(
631→      boxen(chalk.red(`Fatal Error: ${err.message || err}`), {
632→        padding: 1,
633→        margin: 1,
634→        borderColor: "red",
635→      })
636→    );
637→    process.exit(1);
638→  }
639→}
640→
641→// Run main if called directly (only when running this file standalone with Bun)
642→if (typeof Bun !== 'undefined' && import.meta.url.replace("file://", "") === Bun.main) {
643→  cliMain();
644→}
