172→          if (actualClosingTagName.toLowerCase() !== tagName.toLowerCase()) {
173→            addIssue(
174→              issuesList,
175→              {
176→                type: "MalformedTag",
177→                severity: "warning",
178→                subtitleId: contextInfo.currentId,
179→                message: `Found opening tag '<${tagName}>' but next closing tag was '</${actualClosingTagName}>' (expected '${expectedClosingTag}'). Using content anyway.`,
180→                contextSnippet: content.substring(
181→                  openTagIndex,
182→                  Math.min(
183→                    content.length,
184→                    closeTagMarkerIndex + closingTagMatch[0].length + 10
185→                  )
186→                ),
187→              },
188→              contextInfo.searchStartIndex + openTagIndex,
189→              contextInfo.fullContent
190→            );
191→          }
192→        }
193→        return extractedContent;
194→      } else {
195→        addIssue(
196→          issuesList,
197→          {
198→            type: "MalformedTag",
199→            severity: "warning",
200→            subtitleId: contextInfo.currentId,
201→            message: `Found opening tag '<${tagName}>' but no subsequent closing tag marker '</' was found within the parsed block.`,
202→            contextSnippet: content.substring(openTagIndex),
203→          },
204→          contextInfo.searchStartIndex + openTagIndex,
205→          contextInfo.fullContent
206→        );
207→        return null;
208→      }
209→    }
210→  }
211→  return null;
212→}
